async function explainMistake(hand, userBid, correctBid, ruleText) {
  const response = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: "claude-sonnet-4-20250514",
      max_tokens: 300,
      system: `Ты тренер по спортивному бриджу. Объясняй кратко, 2–3 предложения.
               Используй русские обозначения карт: Т К Д В (не A K Q J).
               Масти: ♠ ♥ ♦ ♣. Ссылайся на конкретное правило.`,
      messages: [{
        role: "user",
        content: `Рука: ♠${hand.spades.join('')} ♥${hand.hearts.join('')} ♦${hand.diamonds.join('')} ♣${hand.clubs.join('')}
                  Я заявил: ${userBid}
                  Правильно: ${correctBid}
                  Правило: ${ruleText}
                  Объясни коротко почему я ошибся.`
      }]
    })
  });
  const data = await response.json();
  return data.content[0].text;
}
